import {
  buildReportChartQueryParams as buildCommonChartQueryParams,
  type ErpReportChartCatalogItem,
  type ErpReportDisplayConfig,
} from '@linm-soft-org/linm-web-common-components';
import type { ReportChartOption, JournalLedgerReport } from '../services/analytics/models';

/** Map BE `ReportChartOption[]` → `ErpReportChartCatalogItem[]` for common lib. */
export function mapReportChartCatalog(
  charts: ReportChartOption[] | undefined,
): ErpReportChartCatalogItem[] {
  if (!charts || charts.length === 0) return [];
  return charts.map(c => ({
    chartId: c.chartId,
    title: c.label,
    kind: c.kind,
  }));
}

/**
 * Build chart query params from display config + BE chart catalog.
 */
export function buildReportChartQueryParams(
  config: ErpReportDisplayConfig,
  chartCatalog: ReportChartOption[],
): Record<string, string | number | boolean | undefined> {
  return buildCommonChartQueryParams(config, mapReportChartCatalog(chartCatalog));
}

/** True when displayConfig.chart.showCharts is true and at least one chart is BE-catalog enabled. */
export function isReportChartsEnabled(
  chart: ErpReportDisplayConfig['chart'],
  allowedCharts: ReportChartOption[],
): boolean {
  if (!chart.showCharts) return false;
  if (chart.enabledChartIds.length === 0) return true;
  if (!allowedCharts || allowedCharts.length === 0) return false;
  return allowedCharts.some(c => chart.enabledChartIds.includes(c.chartId));
}

/** True when chart config changed between old and new (triggers re-fetch). */
export function isReportChartConfigChanged(
  oldChart: ErpReportDisplayConfig['chart'],
  newChart: ErpReportDisplayConfig['chart'],
): boolean {
  if (oldChart.showCharts !== newChart.showCharts) return true;
  if (oldChart.showKpiStrip !== newChart.showKpiStrip) return true;
  const oldIds = [...oldChart.enabledChartIds].sort();
  const newIds = [...newChart.enabledChartIds].sort();
  if (oldIds.length !== newIds.length) return true;
  return oldIds.some((id, i) => id !== newIds[i]);
}

export function normalizeJournalLedgerReport(raw: unknown): JournalLedgerReport {
  const d = raw as JournalLedgerReport;
  return {
    items: d?.items ?? [],
    charts: d?.charts ?? [],
    summary: d?.summary ?? { totalDebit: 0, totalCredit: 0, entryCount: 0 },
    chartData: d?.chartData ?? undefined,
    totalCount: d?.totalCount ?? 0,
    page: d?.page ?? 1,
    pageSize: d?.pageSize ?? 0,
  };
}
