export const formatVnd = (value: number | null | undefined): string => {
  if (value == null) return '—';
  return new Intl.NumberFormat('vi-VN', {
    style: 'currency',
    currency: 'VND',
    maximumFractionDigits: 0,
  }).format(value);
};

export const formatDate = (iso: string | null | undefined): string => {
  if (!iso) return '—';
  try {
    return new Date(iso).toLocaleDateString('vi-VN', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
    });
  } catch {
    return iso;
  }
};

export const formatCurrency = formatVnd;

export const formatNumber = (value: number | null | undefined): string => {
  if (value == null) return '—';
  return new Intl.NumberFormat('vi-VN').format(value);
};

export const formatQty = (value: number | null | undefined): string => {
  if (value == null) return '—';
  return new Intl.NumberFormat('vi-VN', { maximumFractionDigits: 2 }).format(value);
};

/**
 * Parse report indicator (name) into STT prefix + label.
 *
 * TT200 reports embed the STT in the name like "A. TÀI SẢN NGẮN HẠN",
 * "I. Tiền và tương đương tiền" or "1. Doanh thu bán hàng…".
 * This extracts the prefix for the STT column and returns the clean label.
 */
export const parseReportStt = (name: string): { stt: string; label: string } => {
  const m = name.match(/^([A-ZĐIVXL\d]+(?:\.[\d]+)?)\.\s*(.*)/s);
  if (m) {
    return { stt: m[1], label: m[2] || name };
  }
  return { stt: '', label: name };
};
